def test_zero_have_count_not_lost(monkeypatch):
    fake_response = {'data': [{'name': 'X-Men', 'year': '2020', 'publisher': 'Marvel', 'status': 'Active', 'have': 0, 'total': 12}]}
    monkeypatch.setattr('homelab_mcp.server._mylar3', lambda: type('M', (), {'call': lambda self, cmd: fake_response})())
    result = mylar3_series()
    assert result['series'][0]['have'] == 0, f"Expected 0 but got {result['series'][0]['have']}"
    assert result['series'][0]['total'] == 12

import threading
from homelab_mcp.server import _clients, _sonarr

def test_concurrent_client_init_single_instance(monkeypatch):
    _clients.clear()
    call_count = {'n': 0}
    original_init = ServarrClient.__init__
    def counting_init(self, *a, **kw):
        call_count['n'] += 1
        original_init(self, *a, **kw)
    monkeypatch.setattr(ServarrClient, '__init__', counting_init)
    threads = [threading.Thread(target=_sonarr) for _ in range(10)]
    for t in threads: t.start()
    for t in threads: t.join()
    assert call_count['n'] == 1, f'Client initialized {call_count["n"]} times (expected 1)'

@pytest.mark.parametrize('tool,invoke,patches', [
    ('kube_restart', lambda mod: mod.kube_restart('default', 'deploy/nginx'), {}),
    ('flux_reconcile', lambda mod: mod.flux_reconcile('kustomization', 'flux-system'), {}),
    ('flux_suspend', lambda mod: mod.flux_suspend('kustomization', 'flux-system'), {}),
    ('flux_resume', lambda mod: mod.flux_resume('kustomization', 'flux-system'), {}),
], ids=['kube_restart','flux_reconcile','flux_suspend','flux_resume'])
def test_ssh_write_tool_entrypoints_block_in_readonly(tool, invoke, patches, monkeypatch):
    mod = _reload_server(readonly=True)
    for name, value in patches.items():
        monkeypatch.setattr(mod, name, value)
    with pytest.raises(RuntimeError, match='readonly mode'):
        invoke(mod)
